import anthropic

def monitor_context_window(messages, model='claude-3-5-sonnet-20240620'):
    client = anthropic.Anthropic()
    total_tokens = 0
    for msg in messages:
        if msg.get('role') == 'assistant' and msg.get('content'):
            for block in msg['content']:
                if block.get('type') == 'tool_use':
                    total_tokens += 50  # XML overhead
                elif block.get('type') == 'text':
                    response = client.count_tokens(block['text'])
                    total_tokens += response.json()['usage']['total_tokens']
    window_limit = 180000  # Safety margin
    overflow_pct = (total_tokens / window_limit) * 100
    return {
        'tokens_used': total_tokens,
        'overflow_risk': overflow_pct > 80,
        'warning': f'Context at {overflow_pct:.1f}% capacity'
    }

def detect_repeated_tool_calls(messages):
    tool_history = []
    repeats = []
    for msg in messages:
        if msg.get('role') == 'assistant' and msg.get('content'):
            for block in msg['content']:
                if block.get('type') == 'tool_use':
                    tool_id = (block['name'], block.get('input', {}))
                    if tool_id in tool_history[-3:]:
                        repeats.append({
                            'tool': block['name'],
                            'input_hash': hash(str(tool_id[1])),
                            'position': len(tool_history)
                        })
                    tool_history.append(tool_id)
    return {'repeated_calls': len(repeats) > 0, 'details': repeats}

def check_history_truncation(current_msg, full_history):
    recent_tools = [m for m in full_history[-10:] if m.get('role') == 'user' and any(b.get('type') == 'tool_result' for b in m.get('content', []))]
    current_text = ' '.join([b['text'] for b in current_msg.get('content', []) if b.get('type') == 'text'])

    missing_references = []
    for tool_result in recent_tools:
        result_id = tool_result['content'][0].get('tool_use_id')
        if result_id and result_id not in current_text:
            missing_references.append(result_id)

    return {'truncation_detected': len(missing_references) > 0, 'missing': missing_references}

