def compress_tool_history(messages, max_tool_results=5):
    compressed = messages.copy()
    tool_summaries = []

    for msg in reversed(messages):
        if msg.get('role') == 'user' and any(b.get('type') == 'tool_result' for b in msg.get('content', [])):
            for block in msg['content']:
                if block.get('type') == 'tool_result':
                    summary = f"Tool '{block['name']}': {block.get('content', '[result]')[:100]}..."
                    tool_summaries.append(summary)
                    if len(tool_summaries) >= max_tool_results:
                        break
            if len(tool_summaries) >= max_tool_results:
                break

    # Replace old history with summaries
    summary_msg = {
        'role': 'system',
        'content': 'Recent tool results: ' + ' | '.join(tool_summaries)
    }
    return [summary_msg] + messages[-3:]

class ClaudeStateManager:
    def __init__(self):
        self.state = {'tools_used': {}, 'key_facts': [], 'task_progress': {}}

    def extract_state(self, messages):
        for msg in messages:
            if msg.get('role') == 'user' and any(b.get('type') == 'tool_result' for b in msg.get('content', [])):
                for block in msg['content']:
                    if block.get('type') == 'tool_result'):
                        tool_name = block['name']
                        self.state['tools_used'][tool_name] = block.get('content', '')
        return self.state

    def inject_state(self, messages):
        state_str = f"Previous state: tools_used={len(self.state['tools_used'])}, facts={len(self.state['key_facts'])}"
        messages.insert(0, {'role': 'system', 'content': state_str})
        return messages
